const drifts = $input.all().map(i => i.json);
if (drifts.length === 0) return [];

// Group by user_id
const byUser = {};
for (const d of drifts) {
  if (!byUser[d.user_id]) byUser[d.user_id] = [];
  byUser[d.user_id].push(d);
}

const signals = [];
for (const [userId, userDrifts] of Object.entries(byUser)) {
  const pages = userDrifts.map(d => d.page_type).join(', ');
  const evidenceUrls = userDrifts.flatMap(d => d.evidence_urls || []);

  signals.push({
    json: {
      signal_type: 'positioning_drift',
      source_platform: 'linkedin',
      company_name: null,
      severity: 4,
      confidence: 0.8,
      title: `High-severity positioning drift detected (${userDrifts.length} events)`,
      summary: `Unresolved high-severity positioning changes detected on ${pages}. ${userDrifts.map(d => d.change_description).join('; ')}`,
      evidence_urls: evidenceUrls,
      source_schema: 'positioning',
      source_table: 'drift_events',
      source_id: userDrifts[0].id,
      meta: {
        user_id: userId,
        drift_count: userDrifts.length,
        page_types: [...new Set(userDrifts.map(d => d.page_type))]
      }
    }
  });
}

return signals;
